@startuml
participant "User_App" as UA
participant "WebRTC_GW" as GW
participant "SkyWay_Server" as SS
participant "Target_Peer" as TP

UA -> GW : POST /peers
{
    key: "YOUR_API_KEY",
    domain: "localhost",
    turn: true,
    peer_id: "media_caller"
}

GW --> UA : 201 Created
{
    command_type: "PEERS_CREATE",
    params:{
        peer_id: "media_caller",
        token: "pt-be74737d-5762-401f-a526-01fa44d98a11"
    }
}

GW -> SS : CREATE PEER

UA -> GW : GET /peers/media_caller/events?
token=pt-be74737d-5762-401f-a526-01fa44d98a11

SS --> GW : SUCCESS
(to bind peer id)

GW --> UA : 200 OK
["event"=>"OPEN",
    params: {
        peer_id: "media_caller",
        token: "pt-be74737d-5762-401f-a526-01fa44d98a11"
    }
]

UA -> GW : POST /media
{
    is_video: true
}

GW --> UA : 201 Created
{
    ip_v4: "172.16.1.106",
    media_id: "vi-9856040d-bd3e-4b33-b121-e3435842e5fc",
    port: 50003
}

UA -> GW : POST /media
{
    is_video: false
}

GW --> UA : 201 Created
{
    ip_v4: "172.16.1.106",
    media_id: "au-a6c4c82c-9d9c-4e12-a52a-c927ec33793e",
    port: 50004
}

UA -> GW : POST /media/rtcp
{}

GW --> UA : 201 Created
{
    "rtcp_id": "rc-970f2e5d-4da0-43e7-92b6-796678c104ad",
    "port": 50003,
    "ip_v4": "172.16.1.106"
}

UA -> GW : POST /media/rtcp
{}

GW --> UA : 201 Created
{
    "rtcp_id": "rc-4044f658-dee5-4aac-a60a-ad133abb4f92",
    "port": 50004,
    "ip_v4": "172.16.1.106"
}

UA -> GW : POST /media/connections
{
    peer_id: "media_caller",
    token: "pt-be74737d-5762-401f-a526-01fa44d98a11",
    target_id: "media_callee",
    constraints:{
        video: true,
        videoReceiveEnabled: true,
        audio: true,
        audioReceiveEnabled: true,
        video_params: {
            band_width: 1500,
            codec: "H264",
            media_id: "vi-9856040d-bd3e-4b33-b121-e3435842e5fc",
            rtcp_id: "rc-970f2e5d-4da0-43e7-92b6-796678c104ad",
            payload_type: 100
        },
        audio_params:{
            band_width: 1500,
            codec: "opus",
            media_id: "au-a6c4c82c-9d9c-4e12-a52a-c927ec33793e",
            rtcp_id: "rc-4044f658-dee5-4aac-a60a-ad133abb4f92",
            payload_type: 111
        }
    },
    redirect_params: {
        video: {
            ip_v4: "172.16.1.105",
            port: 20000
        },
        video_rtcp: {
            ip_v4: "172.16.1.105",
            port: 20010
        },
        audio: {
            ip_v4: "172.16.1.105",
            port: 20001
        },
        audio_rtcp: {
            ip_v4: "172.16.1.105",
            port: 20011
        }
    }
}

GW --> UA : 201 Created
{
    command_type: "MEDIA_CONNECTION_CREATE",
    params: {
        media_connection_id: "mc-55f0b97c-77c7-42d7-b21b-a6a6bc3fee3a"
    }
}

UA -> GW : GET /media/connections
/mc-55f0b97c-77c7-42d7-b21b-a6a6bc3fee3a/events

GW --> UA : 200 OK
[
    event: "READY"
]

loop
UA -> GW : send RTP Video to 172.16.1.106:50001
GW -> TP : redirect Video with MediaStream
UA -> GW : send RTP Audio to 172.16.1.106:50002
GW -> TP : redirect Audio with MediaStream
UA -> GW : send RTCP for Video to 172.16.1.106:50003
GW -> TP : redirect RTCP with MediaStream
UA -> GW : send RTCP for Audio to 172.16.1.106:50004
GW -> TP : redirect RTCP with MediaStream
TP -> GW : recv Video with MediaStream
GW -> UA : redirect RTP Video to 172.16.1.105:20000
TP -> GW : recv Audio with MediaStream
GW -> UA : redirect RTP Audio to 172.16.1.105:20001
TP -> GW : recv RTCP for Video with MediaStream
GW -> UA : redirect RTCP for Video to 172.16.1.105:20010
TP -> GW : recv RTCP for Audio with MediaStream
GW -> UA : redirect RTCP for Audio to 172.16.1.105:20011
end

UA -> GW : Delete /media/connections
/mc-55f0b97c-77c7-42d7-b21b-a6a6bc3fee3a
GW -> TP : Close MediaStream
GW -> TP : erase Video object
and Audio object

GW --> UA : 204 No Content

UA -> GW : Delete /peers/media_caller?token=pt-be74737d-5762-401f-a526-01fa44d98a11
GW -> TP : disconnect

GW --> UA : 204 No Content

@enduml
